/**
  * @brief 	SubmenuHandBluetooth
  * @param angleValue
  * @retval none
  */
static void SubmenuHandBluetooth(unsigned char OnOff)
{	
	OLED_ShowString(40,8,"BLUETOOTH",16,1);	
	DisplayBluetoothIcon(128,8, OnOff);//钃濈墮鍥炬爣
	if(OnOff==0)
	{
		OLED_ShowString(48,40,"OFF",16,0);	
		OLED_ShowString(88,40,"ON",16,1);
	}
	else	
	{
		OLED_ShowString(48,40,"OFF",16,1);	
		OLED_ShowString(88,40,"ON",16,0);
	}		
}
